UPDATE class_checkin
SET class_id = #{classId}, student_id = #{studentId}, bracelet_id = #{braceletId},
    checkin_time = #{checkinTime}, checkout_time = #{checkoutTime}, total_calories = #{totalCalories},
    avg_heart_rate = #{avgHeartRate}, max_heart_rate = #{maxHeartRate}, duration = #{duration}, status = #{status}
WHERE id = #{id}
